INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('4028957d039bec63', 'OH', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for a statewide candidate in Ohio?', '["How much can an individual give to a Governor candidate in OH?","What is the max donation for statewide office in 2026?","OH Governor contribution limits 2026"]', 'For the 2025-2026 cycle, individuals and PACs may contribute a maximum of $16,615.67 per election to a candidate for statewide office. This exact figure is the result of a statutory inflation adjustment calculated by the Secretary of State in odd-numbered years under Ohio Rev. Code § 3517.104. The primary and general count as separate elections.', 'https://www.ohiosos.gov/assets/e-contribution-limits.pdf', 'Ohio Secretary of State – Campaign Contribution Limits', '2026-05-12', 'per_cycle', 'official_source_direct', 'Statewide candidates and donors', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('6dbc44409755cf38', 'OH', '["state"]', 'finance_ethics', 'What are the 2025-2026 contribution limits for State Senate and State House candidates in Ohio?', '["Max donation for OH State Assembly 2026","OH State Senate contribution limits","Are legislative limits different from statewide in Ohio?"]', 'For the 2025-2026 cycle, the contribution limit for individuals and PACs giving to legislative candidates is identical to the statewide limit: $16,615.67 per election. Ohio uniquely applies this same inflation-adjusted ceiling uniformly across Governor, Attorney General, State Senate, and State House candidates.', 'https://www.ohiosos.gov/assets/e-contribution-limits.pdf', 'Ohio Secretary of State – Campaign Contribution Limits', '2026-05-12', 'per_cycle', 'official_source_direct', 'State Legislative candidates and donors', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('299cb83ba226cdbe', 'OH', '["federal","state"]', 'ballot_access', 'How many petition signatures are required for a candidate running for U.S. House, State Senate, or State House?', '["Signature threshold for Congress OH","How many signatures to run for State Assembly OH?","Do independent congressional candidates need more signatures than Republicans?"]', 'For major party candidates seeking a district office (U.S. House, State Senate, State House), the statutory floor is uniquely low: only 50 valid signatures from enrolled party voters within the district. However, Independent candidates face a much steeper hurdle, requiring signatures equal to 1% of the total electors in the district who voted in the preceding gubernatorial election.', 'https://codes.ohio.gov/ohio-revised-code/section-3513.05', 'Ohio Rev. Code § 3513.05', '2026-05-12', 'static', 'statute_citation', 'Congressional and State Legislative candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('1dec0c7d1b13c581', 'OH', '["state"]', 'filing_requirements', 'What is the filing fee for a candidate running for Governor in Ohio?', '["How much does it cost to run for Governor in OH?","Ohio Governor filing fee amount","Does the Lt Governor pay a separate filing fee?"]', 'Candidates for Governor and Lieutenant Governor run on a joint ticket and must collectively pay a total filing fee of $150. This consists of a $100 base fee and an additional $50 surcharge that is directed to the newly created Ohio Election Integrity Commission fund.', 'https://codes.ohio.gov/ohio-revised-code/section-3513.10', 'Ohio Rev. Code § 3513.10(A) and (B)', '2026-05-12', 'per_cycle', 'statute_citation', 'Governor and Lieutenant Governor candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('259f8a560f334086', 'OH', '["federal"]', 'election_dates', 'What is the statutory framework for filling the U.S. Senate vacancy left by JD Vance?', '["How did Jon Husted get the Senate seat?","Why is the Ohio special election in 2026?","Senate appointment mechanics Ohio"]', 'Under Ohio Rev. Code § 3521.02, the Governor appoints a replacement who serves until December 15 following the next regular state election that occurs more than 180 days after the vacancy. A special election is held concurrently with that state election (November 3, 2026) to elect a Senator to serve the remainder of the unexpired term.', 'https://codes.ohio.gov/ohio-revised-code/section-3521.02', 'Ohio Rev. Code § 3521.02', '2026-05-12', 'static', 'statute_citation', 'Federal candidates and consultants', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('0f6555d2b2938384', 'OH', '["federal"]', 'election_dates', 'How long will the winner of the 2026 Ohio U.S. Senate special election serve?', '["Is the 2026 Senate race for a full 6-year term?","When is the next Senate election after 2026?","Term length for Vance replacement"]', 'The winner of the November 3, 2026 special election will serve the unexpired remainder of the current term, which officially ends on January 3, 2029. The incumbent will have to run again in 2028 if they wish to serve a full six-year term.', 'https://codes.ohio.gov/ohio-revised-code/section-3521.02', 'Ohio Rev. Code § 3521.02', '2026-05-12', 'static', 'statute_citation', 'U.S. Senate candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('f47be34c0f164152', 'OH', '["state"]', 'candidate_eligibility', 'Can Governor Mike DeWine run for re-election in 2026?', '["Is the Ohio Governor''s seat open in 2026?","What are the term limits for Ohio Governor?","Can DeWine seek a third term?"]', 'No. The Ohio Constitution strictly limits the Governor to serving two consecutive four-year terms. Since Governor DeWine served terms from 2019-2023 and 2023-2027, he is term-limited and the seat is open for 2026.', 'https://codes.ohio.gov/ohio-constitution/section-3.2', 'Ohio Constitution Article III § 2', '2026-05-12', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('efdef1fa82677927', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When was the 2026 Ohio Primary Election?', '["What date was the OH primary in 2026?","Ohio 2026 primary date","When do polls open for the OH primary?"]', 'The Ohio Primary Election was held on Tuesday, May 5, 2026. Ohio traditionally holds its partisan primaries early in the year, specifically on the first Tuesday after the first Monday in May.', 'https://codes.ohio.gov/ohio-revised-code/section-3501.01', 'Ohio Rev. Code § 3501.01(E)(1)', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('5b89ba6209dbe90f', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'ballot_access', 'What was the candidate filing deadline for major party candidates for the 2026 primary?', '["When did candidates have to file for the 2026 primary in Ohio?","Declaration of candidacy deadline 2026","Ohio 90-day filing rule"]', 'The deadline for partisan candidates to file their declaration of candidacy and designating petitions for the 2026 primary was February 4, 2026, which aligns with Ohio''s requirement to file no later than 4:00 p.m. on the 90th day before the primary election.', 'https://www.ohiosos.gov/assets/candidate-requirement-guide-2026.pdf', 'Ohio Secretary of State – 2026 Candidate Requirement Guide', '2026-05-12', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('e09437071ddd9629', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 Ohio General Election?', '["What date is the OH general election in 2026?","OH 2026 midterm election date","When is Election Day 2026 in Ohio?"]', 'The Ohio General Election is scheduled for Tuesday, November 3, 2026.', 'https://codes.ohio.gov/ohio-revised-code/section-3501.01', 'Ohio Rev. Code § 3501.01(A)', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('ba96df6e3b2c6be6', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the voter registration deadline for the November 2026 General Election?', '["When is the last day to register for the 2026 general election in OH?","General election registration deadline OH 2026","Ohio 30-day voter registration rule"]', 'Voter registration in Ohio closes 30 days prior to the election. For the November 3, 2026 General Election, all voter registration applications must be submitted or postmarked by October 5, 2026.', 'https://codes.ohio.gov/ohio-revised-code/section-3503.19', 'Ohio Rev. Code § 3503.19(A)', '2026-05-12', 'per_cycle', 'statute_citation', 'All unregistered voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('d793d4b3d1a2df02', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Is a photo ID required to vote in person in Ohio?', '["Ohio voter ID laws","Do I need my driver''s license to vote in OH?","HB 458 photo ID requirement"]', 'Yes. Under HB 458, Ohio voters must present a valid, unexpired photo ID to vote in person on Election Day or during early voting. Acceptable forms include an Ohio driver''s license, an Ohio state ID, a U.S. passport/passport card, or a U.S. military/VA ID card. Utility bills and bank statements are no longer accepted.', 'https://www.ohiosos.gov/elections/voters/id-requirements/', 'Ohio Secretary of State – Voter ID Requirements', '2026-05-12', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('c99332923d8ab300', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How many days of early voting are available in Ohio?', '["Early voting period Ohio","When does early voting start in OH?","Does Ohio have weekend voting?"]', 'Ohio offers a robust 28 days of early in-person voting prior to Election Day, which includes some weekend hours. Early voting begins on the day after the close of the voter registration window.', 'https://codes.ohio.gov/ohio-revised-code/section-3509.01', 'Ohio Rev. Code § 3509.01', '2026-05-12', 'static', 'statute_citation', 'All voters and Get-Out-The-Vote operations', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('352ae937953ba18d', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does Ohio have same-day voter registration?', '["Can I register to vote at the polls in Ohio?","Same-day registration rules OH","Conditional voter registration Ohio"]', 'No. Ohio does not allow same-day voter registration. Eligible citizens must ensure their registration is processed by the 30-day deadline before an election to be permitted to vote.', 'https://codes.ohio.gov/ohio-revised-code/section-3503.19', 'Ohio Rev. Code § 3503.19', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('5ea1d9a82e8aea71', 'OH', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can a corporation contribute directly to a candidate for state office in Ohio?', '["Are corporate contributions legal in OH?","Can my business donate to a state candidate?","Ohio corporate donation rules"]', 'No. Ohio law explicitly prohibits corporations, non-profit corporations, and LLCs treated as corporations from using their general treasury funds to make direct contributions to state or local candidates, or to political parties. They may, however, establish and administer an affiliated PAC.', 'https://codes.ohio.gov/ohio-revised-code/section-3599.03', 'Ohio Rev. Code § 3599.03', '2026-05-12', 'static', 'statute_citation', 'Corporations and Campaign Treasurers', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('7a4732149b2c45f2', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'runoff_rules', 'What triggers an automatic recount in Ohio elections?', '["Automatic recount margin Ohio","When is a recount required by law in OH?","0.5% recount rule"]', 'An automatic recount is legally triggered in Ohio if the margin of victory between the winning and losing candidate is equal to or less than 0.5% of the total votes cast for that state or federal office. For statewide ballot issues, the automatic trigger is a narrower 0.25%.', 'https://codes.ohio.gov/ohio-revised-code/section-3515.011', 'Ohio Rev. Code § 3515.011', '2026-05-12', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('b7563b4224f972f7', 'OH', '["federal"]', 'redistricting', 'Which congressional maps are in effect for the 2026 election cycle in Ohio?', '["Did Ohio redraw its congressional districts for 2026?","Mid-decade redistricting status OH","Are we using new maps for Congress in 2026?"]', 'The mid-decade congressional maps adopted by the Ohio Redistricting Commission in 2025 are in effect for the 2026 cycle. These maps replaced the previous boundaries drawn earlier in the decade.', 'https://redistricting.ohio.gov/', 'Ohio Redistricting Commission', '2026-05-12', 'volatile', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('004d1794d275487e', 'OH', '["federal","state"]', 'redistricting', 'Who is responsible for drawing state legislative and congressional maps in Ohio?', '["Who is on the Ohio Redistricting Commission?","ORC composition","Does the legislature draw the maps in OH?"]', 'Redistricting authority lies with the Ohio Redistricting Commission (ORC). The ORC is a 7-member body consisting of the Governor, Auditor of State, Secretary of State, and four legislative appointees (one from the majority and minority leaders of both the State Senate and State House).', 'https://codes.ohio.gov/ohio-constitution/section-11.1', 'Ohio Constitution Article XI § 1', '2026-05-12', 'static', 'statute_citation', 'State Legislative and Congressional Candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('dc901701bcc50228', 'OH', '["federal","state"]', 'filing_requirements', 'What is the filing fee for a candidate running for U.S. House or the State Legislature?', '["Cost to run for OH State House","State Senate filing fee OH","How much is the congressional filing fee in Ohio?"]', 'The total filing fee for a district office, which encompasses the U.S. House of Representatives, the Ohio State Senate, and the Ohio State House, is $85. This includes a $50 base fee and a $35 Elections Integrity Commission surcharge.', 'https://codes.ohio.gov/ohio-revised-code/section-3513.10', 'Ohio Rev. Code § 3513.10(A) and (B)', '2026-05-12', 'per_cycle', 'statute_citation', 'Congressional and State Legislative candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('2077797c98e4322f', 'OH', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'When is the filing deadline for Independent candidates in Ohio?', '["Running as an independent in OH","Independent line ballot access Ohio","How do unaffiliated candidates get on the ballot?"]', 'Independent candidates who wish to bypass the primary and appear directly on the November general election ballot must file their Nominating Petition and Statement of Candidacy by 4:00 p.m. on the day immediately preceding the primary election. For the 2026 cycle, this deadline was May 4, 2026.', 'https://www.ohiosos.gov/assets/candidate-requirement-guide-2026.pdf', 'Ohio Secretary of State – 2026 Candidate Requirement Guide', '2026-05-12', 'per_cycle', 'official_source_direct', 'Independent and third-party candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('5e5bdef3190aa698', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in Ohio?', '["Felon voting rights OH","Can I vote after getting out of prison in Ohio?","Voting post-incarceration rules OH"]', 'Yes. Ohio law provides that a person''s right to vote is automatically restored immediately upon their release from a penal institution. Individuals currently serving time on parole, probation, or under community control are fully eligible to register and vote.', 'https://codes.ohio.gov/ohio-revised-code/section-2961.01', 'Ohio Rev. Code § 2961.01', '2026-05-12', 'static', 'statute_citation', 'All eligible citizens', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('de2cbf6dd91796d1', 'OH', '["county","municipal"]', 'voter_interaction', 'How many absentee ballot drop boxes are permitted per county in Ohio?', '["Are ballot drop boxes restricted in OH?","Where can I drop off my mail ballot?","County limits for mail ballot boxes"]', 'Under Ohio law and directives issued by the Secretary of State, each county board of elections is restricted to operating a single, centralized secure drop box location. This drop box must be situated on the property of the county board of elections office and monitored continuously.', 'https://codes.ohio.gov/ohio-revised-code/section-3509.05', 'Ohio Rev. Code § 3509.05', '2026-05-12', 'static', 'statute_citation', 'Voters and Get-Out-The-Vote operations', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('64a88b6e989ec3fa', 'OH', '["state"]', 'candidate_eligibility', 'What are the term limits for members of the Ohio State Legislature?', '["How long can someone serve in the OH Assembly?","State Representative term limits OH","State Senate consecutive terms"]', 'The Ohio Constitution restricts state legislators to eight consecutive years in a single chamber. State Representatives are limited to four consecutive two-year terms, while State Senators are limited to two consecutive four-year terms. A member may run for the other chamber after hitting their limit.', 'https://codes.ohio.gov/ohio-constitution/section-2.2', 'Ohio Constitution Article II § 2', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('e995425bf08e5306', 'OH', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the procedure for running as a write-in candidate in Ohio?', '["Do write-in candidates have to register in OH?","How to legally canvass write-in votes","Declaration of Intent to be a Write-In Candidate"]', 'Voters can write in names on the ballot, but votes are only tallied for officially registered candidates. A write-in candidate must file a ''Declaration of Intent to be a Write-In Candidate'' with the Board of Elections no later than 72 days before the election (February 23, 2026 for the primary, August 24, 2026 for the general).', 'https://www.boe.ohio.gov/summit/c/upload/ElectionsCalendar.pdf', 'Ohio Secretary of State – 2026 Elections Calendar', '2026-05-12', 'per_cycle', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('21d63457097b613e', 'OH', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the periodic and pre-election reporting schedule for campaign committees in Ohio?', '["When are campaign finance reports due in OH?","12-day pre-primary report deadline","Ohio periodic campaign filing dates"]', 'Campaign committees must file a Pre-Election report 12 days before the election, and a Post-Election report 38 days after the election. Additionally, committees must file an Annual Report on the last business day of January. During non-election years, a Semiannual Report is also required by the last business day of July.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.10', 'Ohio Rev. Code § 3517.10(A)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('a2948f26b6395085', 'OH', '["state","county","municipal","judicial"]', 'finance_ethics', 'When must a candidate formally designate a campaign treasurer in Ohio?', '["Designation of Treasurer deadline OH","When to register a campaign committee in Ohio","Can I spend money before designating a treasurer?"]', 'A candidate must file a Designation of Treasurer form with the Secretary of State or county board of elections before receiving any contributions or making any expenditures. No campaign activity can legally occur until this form is processed.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.081', 'Ohio Rev. Code § 3517.081', '2026-05-12', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('692131e650c9a528', 'OH', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the difference between the Ohio Election Integrity Commission (OEIC) and the Election Integrity Unit (EIU)?', '["Are the OEIC and EIU the same thing?","Who investigates campaign complaints vs voter fraud in OH?","Ohio Election Integrity Commission vs Unit"]', 'They are separate, parallel bodies. The OEIC (established via SB 293) exclusively handles campaign finance violations, succeeding the OEC. The EIU (established via SB 4) is a separate unit within the Secretary of State''s office that exclusively investigates election fraud and voter suppression.', 'https://www.legislature.ohio.gov/legislation/136/sb293', 'Ohio SB 293 / SB 4 (136th General Assembly)', '2026-05-12', 'static', 'statute_citation', 'Candidates, Consultants, and Legal Counsel', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('809e46517c43044b', 'OH', '["state","county","municipal","judicial"]', 'finance_ethics', 'Where do I file a campaign finance complaint versus an election fraud complaint in Ohio?', '["Reporting an opponent for campaign finance violations OH","Who handles illegal voting complaints vs donor limits?","Filing process for election crimes Ohio"]', 'Under the 2026 framework, campaign finance complaints must be filed directly with the Ohio Election Integrity Commission (OEIC). Conversely, allegations of voter suppression or election fraud must be filed with the Election Integrity Unit (EIU) within the Secretary of State''s office.', 'https://www.ohiosos.gov/assets/dir2026-17-ohio-election-integrity-commission-and-election-integrity-unit.pdf', 'Ohio Secretary of State – Directive 2026-17', '2026-05-12', 'static', 'official_source_direct', 'Voters, Opponents, and Election Officials', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('2d3596aae86cd579', 'OH', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for filing a campaign finance report late in Ohio?', '["Late filing fees OH","How much is the fine for missing a reporting deadline?","OEIC campaign finance fines"]', 'Under Ohio Rev. Code § 3517.992, the OEIC has the authority to assess civil penalties for late reports. Fines typically range from $15 to $100 per day depending on the specific form, the office level, and the length of the delinquency.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.992', 'Ohio Rev. Code § 3517.992', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('e816bfd6e594fdd9', 'OH', '["state","county","municipal"]', 'finance_ethics', 'How long must a campaign treasurer retain campaign finance records in Ohio?', '["Campaign record retention requirements OH","How many years to keep campaign receipts?","Audit record retention Ohio"]', 'Under Ohio law, a campaign treasurer must preserve all receipted bills, bank statements, and accounts related to their campaign finance disclosure statements for six years following the filing of the statement.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.10', 'Ohio Rev. Code § 3517.10', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('8603dacc4930c00f', 'OH', '["state","county","municipal"]', 'finance_ethics', 'What are the rules for disposing of surplus campaign funds in Ohio?', '["Surplus funds disposition OH","Can I give my leftover campaign money to charity?","What happens to campaign money when I close my committee?"]', 'Surplus campaign funds cannot be converted to personal use. They may be refunded pro-rata to contributors, donated to a 501(c)(3) tax-exempt charity, or remitted to the state treasury to the credit of the newly established Ohio Election Integrity Commission fund.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.109', 'Ohio Rev. Code § 3517.109(C)', '2026-05-12', 'static', 'statute_citation', 'Candidates concluding campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('42d6263f264d7888', 'OH', '["state","county","municipal"]', 'finance_ethics', 'Are foreign nationals prohibited from contributing to state and local campaigns in Ohio?', '["Can a foreign citizen donate to my city council race?","Foreign contribution ban OH","Are non-citizens allowed to fund independent expenditures in Ohio?"]', 'Yes. Ohio law completely mirrors federal restrictions, prohibiting foreign nationals from making contributions, directly or indirectly, to any state or local candidate, or funding any independent expenditures or electioneering communications.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.13', 'Ohio Rev. Code § 3517.13(W)', '2026-05-12', 'static', 'statute_citation', 'All state and local campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('74995880cacb0318', 'OH', '["state","county","municipal"]', 'finance_ethics', 'What triggers the requirement to report an Independent Expenditure in Ohio?', '["When does an independent group have to file?","Independent expenditure definition OH","Reporting threshold for Super PACs Ohio"]', 'Under Ohio Admin. Code 111:2-2 and RC 3517.105, any person or entity making independent expenditures (communications advocating election/defeat without coordination) aggregating in excess of $500 must file disclosure statements with the Secretary of State or county board.', 'https://codes.ohio.gov/ohio-administrative-code/chapter-111:2-2', 'Ohio Admin. Code 111:2-2', '2026-05-12', 'static', 'statute_citation', 'Super PACs and Independent Expenditure Committees', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('7828b6fa64877859', 'OH', '["state","county","municipal"]', 'finance_ethics', 'What is the 24-hour reporting rule for Independent Expenditures in Ohio?', '["Late independent expenditure reporting OH","When do I have to report PAC spending within 24 hours?","24-hour rule for $10,000 expenditures"]', 'Under Ohio Rev. Code § 3517.105(B), any independent expenditure of $10,000 or more made during the period beginning 90 days before the primary election and ending on the day of the general election must be reported within 24 hours.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.105', 'Ohio Rev. Code § 3517.105(B)', '2026-05-12', 'static', 'statute_citation', 'Super PACs and IECs', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('6d5dd7939b790b67', 'OH', '["state"]', 'candidate_eligibility', 'What are the specific residency requirements to run for the Ohio State Legislature?', '["How long do I have to live in OH to run for State Senate?","Residency rules State Assembly OH","Do I have to live in the district to run?"]', 'Under the Ohio Constitution, a candidate for State Senate or State Representative must have resided in their respective district for one year immediately preceding their election.', 'https://codes.ohio.gov/ohio-constitution/section-2.3', 'Ohio Constitution Article II § 3', '2026-05-12', 'static', 'statute_citation', 'State Legislative Candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('41620939711bab23', 'OH', '["federal"]', 'candidate_eligibility', 'What are the specific residency and age requirements to run for U.S. House in Ohio?', '["Do I have to live in the district to run for Congress in OH?","Age requirement for Congress Ohio","Can I run for a congressional seat if I live in a different district?"]', 'A U.S. House candidate must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of Ohio when elected. The U.S. Constitution does not require the candidate to live within the specific congressional district boundaries.', 'https://www.ohiosos.gov/assets/candidate-requirement-guide-2026.pdf', 'Ohio Secretary of State / U.S. Constitution Art. I § 2', '2026-05-12', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('a272313fea3c4dc2', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What are the state restrictions on placing campaign signs near highways in Ohio?', '["Can I put political signs on state roads?","ODOT campaign sign rules","Where are campaign signs prohibited in OH?"]', 'The Ohio Department of Transportation (ODOT) strictly prohibits the placement of political campaign signs within the state highway right-of-way. Signs placed illegally are subject to immediate removal by ODOT crews without notice.', 'https://codes.ohio.gov/ohio-revised-code/chapter-5515', 'Ohio Rev. Code Chapter 5515', '2026-05-12', 'static', 'statute_citation', 'All campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('56d2008e9e7fcdaa', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the disclosure requirements for campaign text messages (SMS) and robocalls in Ohio?', '["Do campaign texts need an ''Ad paid for by'' disclaimer?","Robocall disclosure requirements OH","SMS political rules Ohio"]', 'A readable and/or audible disclaimer identifying who paid for the communication must be included on almost everything created to influence an election in Ohio. This explicitly includes electronic messages, text messages (SMS), and robocalls.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.20', 'Ohio Rev. Code § 3517.20', '2026-05-12', 'static', 'statute_citation', 'All campaigns utilizing digital communication', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('c7c8da6fe301413b', 'OH', '["state","county","municipal"]', 'finance_ethics', 'Are candidates in Ohio allowed to use campaign funds for personal expenses?', '["Personal use of campaign funds OH","Can I buy a car with campaign money?","Ohio rules on spending campaign donations"]', 'No. Ohio Rev. Code § 3517.13 strictly prohibits any beneficiary of a campaign fund from converting anything of value from the fund to personal use. Expenses must be legitimate, verifiable, and ordinarily necessary to the campaign or duties of public office.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.13', 'Ohio Rev. Code § 3517.13(O)', '2026-05-12', 'static', 'statute_citation', 'All state and local candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('72dd58676e7ec2e1', 'OH', '["state"]', 'ballot_access', 'What was the outcome of the November 2023 constitutional amendment regarding reproductive rights (Issue 1)?', '["Did the Ohio abortion amendment pass?","Issue 1 November 2023 outcome","Reproductive rights initiative Ohio"]', 'In November 2023, Ohio voters approved Issue 1, a citizen-initiated constitutional amendment that enshrined a right to reproductive freedom in the state constitution. It passed with roughly 56% of the vote.', 'https://www.ohiosos.gov/elections/election-results-and-data/2023-official-election-results/', 'Ohio Secretary of State – 2023 Election Results', '2026-05-12', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('4f60ef02c968eb16', 'OH', '["state"]', 'ballot_access', 'What was the outcome of the August 2023 constitutional amendment regarding the 60% passage threshold (Issue 1)?', '["Did the Ohio 60 percent threshold pass?","Issue 1 August 2023 outcome","Does a ballot initiative require a supermajority in OH?"]', 'In an August 2023 special election (Issue 1), Ohio voters decisively rejected a legislative proposal that would have raised the passage threshold for constitutional amendments to a 60% supermajority. Therefore, citizen-initiated constitutional amendments still require only a simple majority to pass.', 'https://www.ohiosos.gov/elections/election-results-and-data/2023-official-election-results/', 'Ohio Secretary of State – 2023 Election Results', '2026-05-12', 'static', 'official_source_direct', 'Ballot measure committees and Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('92d45d63080431c8', 'OH', '["state"]', 'ballot_access', 'What was the outcome of the November 2023 statutory initiative regarding recreational cannabis (Issue 2)?', '["Did Ohio legalize weed in 2023?","Issue 2 November 2023 outcome","Recreational cannabis statute Ohio"]', 'In November 2023, Ohio voters approved Issue 2, a citizen-initiated statute that legalized the cultivation, processing, sale, and use of recreational cannabis for adults 21 and older. It passed with roughly 57% of the vote.', 'https://www.ohiosos.gov/elections/election-results-and-data/2023-official-election-results/', 'Ohio Secretary of State – 2023 Election Results', '2026-05-12', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('f922884356a0d926', 'OH', '["state"]', 'redistricting', 'What was the outcome of the ''Citizens Not Politicians'' redistricting amendment (Issue 1) in 2024?', '["Did the 2024 redistricting amendment pass in Ohio?","Citizens Not Politicians November 2024 results","Issue 1 2024 gerrymandering vote"]', 'The ''Citizens Not Politicians'' constitutional amendment, which would have replaced the politician-led Ohio Redistricting Commission with an independent 15-member citizen commission, was defeated by Ohio voters in the November 2024 general election by a margin of 53.7% to 46.3%.', 'https://www.ohiosos.gov/elections/election-results-and-data/', 'Ohio Secretary of State – 2024 Election Results', '2026-05-12', 'static', 'official_source_direct', 'All Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('ef4a359769492ac4', 'OH', '["state"]', 'ballot_access', 'How many valid signatures are required to qualify a citizen-initiated constitutional amendment in Ohio?', '["Signature requirement for Ohio constitutional amendment","How many signatures to change the Ohio constitution?","10% gubernatorial vote rule"]', 'Qualifying a constitutional amendment requires valid signatures equal to at least 10% of the total votes cast for Governor in the previous election. Based on the 2022 turnout of 4,134,877, this strictly translates to 413,488 valid signatures.', 'https://www.ohioattorneygeneral.gov/Legal/Ballot-Initiatives/Initiative-and-Referendum-Signature-Requirements', 'Ohio Attorney General – Signature Requirements', '2026-05-12', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('6ae77fcd191f3f9e', 'OH', '["state"]', 'ballot_access', 'How many valid signatures are required to qualify a citizen-initiated statute in Ohio?', '["Signature requirement for Ohio initiated statute","How many signatures to pass a law by ballot in OH?","3% gubernatorial vote rule"]', 'Qualifying an initiated statute requires valid signatures equal to at least 3% of the total votes cast for Governor in the previous election. Based on the 2022 turnout, this translates to 124,046 valid signatures.', 'https://www.ohioattorneygeneral.gov/Legal/Ballot-Initiatives/Initiative-and-Referendum-Signature-Requirements', 'Ohio Attorney General – Signature Requirements', '2026-05-12', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('af363b80b5a55a9d', 'OH', '["state"]', 'ballot_access', 'What is the geographic distribution requirement for ballot initiative signatures in Ohio?', '["Do I need signatures from every county in OH?","44 county signature rule Ohio","Geographic distribution constitutional amendment"]', 'For any statewide initiative or referendum, organizers must collect signatures from at least 44 of Ohio''s 88 counties. Within each of those 44 counties, the signatures collected must meet a proportional percentage of that specific county''s gubernatorial vote (e.g., 5% for an amendment, 1.5% for a statute).', 'https://www.ohioattorneygeneral.gov/Legal/Ballot-Initiatives/Initiative-and-Referendum-Signature-Requirements', 'Ohio Attorney General – Signature Requirements', '2026-05-12', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('4d52930716374361', 'OH', '["state"]', 'election_dates', 'How are vacancies in the Ohio State Legislature filled?', '["Special election for State Assembly OH","How is a vacant state senate seat filled?","Do special elections have primaries in OH?"]', 'Legislative vacancies are not filled by special elections. Instead, under Article II § 11 of the Ohio Constitution, the vacancy is filled by an appointment voted on by the remaining members of the chamber who are affiliated with the same political party as the former member.', 'https://codes.ohio.gov/ohio-constitution/section-2.11', 'Ohio Constitution Article II § 11', '2026-05-12', 'static', 'statute_citation', 'State Legislative Candidates and Party Caucuses', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('f5571d7356970f2e', 'OH', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can public funds be used to support or oppose campaigns in Ohio?', '["Can the city council spend tax money on a levy campaign?","Auditor of State bulletin 2025 public funds","Charter entity exemption elimination"]', 'No. Ohio Rev. Code § 9.03(C) universally prohibits public funds from supporting or opposing campaigns. Under Am. Sub. H.B. 96, effective September 30, 2025, the previous exemption for charter municipalities and counties was explicitly eliminated, applying the ban uniformly across all 88 counties.', 'https://ohioauditor.gov/publications/docs/Ohio_Auditor_of_State_Levy_FAQ.pdf', 'Ohio Auditor of State – Levy FAQ', '2026-05-12', 'static', 'official_source_direct', 'Local officials and Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('e7a940ada7ea6fbb', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Under what circumstances is a provisional ballot used at an Ohio polling place?', '["When do I have to cast a provisional ballot?","Are provisional ballots counted in OH?","Voting if my ID is rejected"]', 'Provisional ballots are issued to voters whose eligibility cannot be immediately confirmed on Election Day (e.g., lack of strict photo ID, change of address not updated, or name missing from the poll book). These are set aside and counted only after the board of elections verifies the voter''s eligibility.', 'https://www.ohiosos.gov/elections/voters/provisional-voting/', 'Ohio Secretary of State – Provisional Voting', '2026-05-12', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('cd5f12caabae78a0', 'OH', '["state"]', 'candidate_eligibility', 'What are the specific residency requirements to run for a statewide executive office in Ohio?', '["How long do I need to live in OH to run for Governor?","Residency rules for Attorney General","Do I have to be a resident for 5 years to run for Treasurer?"]', 'Under the Ohio Constitution, candidates for Governor, Attorney General, Secretary of State, Auditor, and Treasurer must be qualified electors and residents of Ohio. Unlike some states, Ohio does not enforce a multi-year durational residency requirement for these executive offices prior to election.', 'https://codes.ohio.gov/ohio-constitution', 'Ohio Constitution Article III / Article XV § 4', '2026-05-12', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('5179574c19003e55', 'OH', '["state"]', 'candidate_eligibility', 'What is the minimum age to run for Governor or other statewide executive offices in Ohio?', '["How old do you have to be to be OH Governor?","Age requirement for Attorney General","Gubernatorial candidate age limit Ohio"]', 'A candidate for statewide executive office in Ohio (Governor, Attorney General, Secretary of State, Auditor, Treasurer) must be at least 18 years old, which satisfies the constitutional requirement of being a qualified elector.', 'https://codes.ohio.gov/ohio-constitution', 'Ohio Constitution Article XV § 4', '2026-05-12', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('22cfbe6e861efe7a', 'OH', '["state"]', 'candidate_eligibility', 'What are the term limits for the Attorney General, Secretary of State, Auditor, and Treasurer in Ohio?', '["How long can someone serve as Secretary of State in OH?","State Auditor term limits OH","Executive office consecutive terms Ohio"]', 'Under the Ohio Constitution, the Attorney General, Secretary of State, Auditor, and Treasurer are strictly limited to serving two consecutive four-year terms, mirroring the Governor''s term limit.', 'https://codes.ohio.gov/ohio-constitution/section-3.2', 'Ohio Constitution Article III § 2', '2026-05-12', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('f1bab7636e61a125', 'OH', '["federal","state","county","municipal","judicial"]', 'election_dates', 'What authority does the Ohio Secretary of State have over elections?', '["Who runs elections in Ohio?","Secretary of State election powers","Chief Election Officer OH"]', 'The Ohio Secretary of State is the state''s Chief Election Officer, responsible for administering elections, compiling campaign finance reports, certifying ballot access for statewide candidates, and issuing directives to oversee the 88 county boards of elections.', 'https://www.ohiosos.gov/elections/', 'Ohio Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'All Campaigns and Voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('eb8aab30e7fddcf9', 'OH', '["state","county","municipal"]', 'finance_ethics', 'What is the Ohio Auditor''s role regarding campaign finance and elections?', '["Who audits the Ohio Election Integrity Commission?","Auditor of State campaign oversight","Does the Auditor enforce the public funds ban?"]', 'The Ohio Auditor of State is responsible for auditing public entities to ensure compliance with laws like the RC 9.03 public funds ban, and performs audits of the newly established Ohio Election Integrity Commission fund.', 'https://ohioauditor.gov/', 'Ohio Auditor of State', '2026-05-12', 'static', 'official_source_direct', 'Campaign Treasurers and Public Officials', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('710a6fdbfd17ffab', 'OH', '["state"]', 'election_dates', 'How are vacancies filled for statewide executive offices like Attorney General or Secretary of State?', '["Who replaces the Ohio Auditor if they resign?","Statewide office vacancy fill procedure","Does the Governor appoint the Attorney General?"]', 'If a vacancy occurs in the office of Auditor, Treasurer, Secretary of State, or Attorney General, the Governor appoints a replacement to serve until the next general election that occurs more than 40 days after the vacancy.', 'https://codes.ohio.gov/ohio-constitution/section-3.18', 'Ohio Constitution Article III § 18', '2026-05-12', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('aacc4b810b38e7c4', 'OH', '["federal"]', 'election_dates', 'How are vacancies in the U.S. House of Representatives filled in Ohio?', '["Special election for Congress OH","Does the Governor appoint US House replacements in Ohio?","Congressional vacancy procedure"]', 'Vacancies in the U.S. House of Representatives are filled exclusively by a special election called by the Governor. Unlike U.S. Senate vacancies, the Governor cannot appoint an interim U.S. Representative.', 'https://codes.ohio.gov/ohio-revised-code/section-3521.03', 'Ohio Rev. Code § 3521.03', '2026-05-12', 'static', 'statute_citation', 'U.S. House candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('5ef493a40d87b302', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'On what dates can special elections be scheduled in Ohio?', '["Special election dates OH","When can a local levy be voted on?","Ohio special election calendar"]', 'Under Ohio Rev. Code § 3501.01, special elections can generally only be scheduled on the first Tuesday after the first Monday in February, May, August, or November.', 'https://codes.ohio.gov/ohio-revised-code/section-3501.01', 'Ohio Rev. Code § 3501.01(D)', '2026-05-12', 'static', 'statute_citation', 'All Campaigns and Local Officials', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('49d3a74347ceb30e', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the deadline for a mail-in absentee ballot to be received by the board of elections?', '["When is my absentee ballot due in OH?","Mail ballot receipt deadline SB 293","Ohio postmark rules for mail voting"]', 'Under SB 293 (effective March 2026), all regular civilian absentee ballots returned by mail must be physically received by the board of elections by the close of polls (7:30 p.m.) on Election Day. This eliminated the previous four-day postmark grace period.', 'https://www.legislature.ohio.gov/legislation/136/sb293', 'Ohio SB 293 (136th General Assembly)', '2026-05-12', 'static', 'statute_citation', 'All voters and Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('e635a116af429823', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How does Ohio verify the citizenship of registered voters?', '["Noncitizen voter removal OH","SB 293 citizenship verification","Does Ohio cross check voter rolls with the BMV?"]', 'Under SB 293, the Secretary of State is mandated to conduct regular, monthly cross-checks of voter rolls against Bureau of Motor Vehicles (BMV) and Social Security Administration (SSA) data to identify and remove noncitizens from the registry.', 'https://www.legislature.ohio.gov/legislation/136/sb293', 'Ohio SB 293 (136th General Assembly)', '2026-05-12', 'static', 'statute_citation', 'Voters and Election Officials', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('0624132770b56c91', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How long does a voter have to cure a provisional ballot cast due to a lack of photo ID?', '["Provisional ballot curing window OH","How many days to show ID after voting provisionally?","Curing an ID mismatch Ohio"]', 'Voters who cast a provisional ballot because they lacked strict photo ID have until the fourth day after the election to cure their ballot by presenting a qualifying, unexpired photo ID in person at their county board of elections.', 'https://www.ohiosos.gov/elections/voters/provisional-voting/', 'Ohio Secretary of State – Provisional Voting', '2026-05-12', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('27f2027742a3a89b', 'OH', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the polling place electioneering buffer zone in Ohio?', '["How close to the door can I campaign in OH?","100-foot rule Ohio voting","Campaign signs at polling places"]', 'Ohio enforces a strict 100-foot electioneering buffer zone measured from the entrance of the polling place. No campaign signs, literature distribution, or candidate advocacy can legally occur within this boundary.', 'https://codes.ohio.gov/ohio-revised-code/section-3501.35', 'Ohio Rev. Code § 3501.35', '2026-05-12', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('6d6919fadfc3d226', 'OH', '["state","federal"]', 'recall_rules', 'Can voters recall a statewide official or state legislator in Ohio?', '["Statewide recall mechanism OH","How to recall the Governor in Ohio","Can we recall a state senator?"]', 'Ohio does not have a constitutional or statutory mechanism for the recall of statewide officials, state legislators, or federal representatives. Recall mechanisms only exist at the local level if specifically authorized by a municipal charter.', 'https://codes.ohio.gov/ohio-constitution', 'Ohio Constitution', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('f5fdc1e01a1bd138', 'OH', '["judicial"]', 'election_dates', 'How are justices selected for the Ohio Supreme Court?', '["Are Supreme Court judges elected in OH?","Supreme court partisan elections Ohio","How long do OH highest court judges serve?"]', 'The Ohio Supreme Court consists of seven justices elected to six-year terms. Following a 2021 law, candidates for the Supreme Court and appellate courts now run in partisan primaries and appear with their specific party affiliation on the general election ballot.', 'https://www.supremecourt.ohio.gov/courts/judicial-system/supreme-court-of-ohio/justices-overview/', 'Supreme Court of Ohio', '2026-05-12', 'static', 'official_source_direct', 'Judicial Candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('c557efb4b9cacfb7', 'OH', '["judicial"]', 'election_dates', 'How are Ohio Court of Appeals judges selected?', '["Appellate court judicial elections OH","Are appellate judges partisan in Ohio?","Court of appeals term length"]', 'Ohio Court of Appeals judges are elected to six-year terms in partisan elections. The state is divided into 12 appellate districts, and any vacancies that occur between elections are filled by gubernatorial appointment.', 'https://www.supremecourt.ohio.gov/courts/judicial-system/ohio-court-of-appeals/', 'Supreme Court of Ohio', '2026-05-12', 'static', 'official_source_direct', 'Judicial Candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('c380c6869af06e4d', 'OH', '["judicial"]', 'election_dates', 'How are local trial court judges elected in Ohio?', '["Municipal court judge elections OH","Are trial judges nonpartisan in Ohio?","Courts of Common Pleas selection"]', 'Candidates for Municipal Courts and Courts of Common Pleas run in partisan primary elections to secure a nomination, but they appear on the November general election ballot without any party affiliation (a nonpartisan general election).', 'https://pressbooks.ulib.csuohio.edu/statelocalgov/chapter/11-11-judicial-selection/', 'Ohio Judicial Selection Guide', '2026-05-12', 'static', 'secondary_source', 'Local Judicial Candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('8e9e0c1757ae7092', 'OH', '["county"]', 'election_dates', 'When are county prosecutors and sheriffs elected in Ohio?', '["County prosecutor election mechanics","When do we vote for sheriff in OH?","Are sheriff races partisan?"]', 'County prosecutors and sheriffs are elected in partisan elections to four-year terms. These county-level executive elections are statutorily scheduled to coincide with the presidential election cycle.', 'https://codes.ohio.gov/ohio-revised-code', 'Ohio Rev. Code', '2026-05-12', 'static', 'statute_citation', 'County-level Candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('8da7c40899697116', 'OH', '["municipal","special_district"]', 'election_dates', 'When are municipal and local school board elections held in Ohio?', '["Odd-year elections Ohio","When do we vote for mayor in OH?","School board election scheduling"]', 'Municipal and local school board elections in Ohio are statutorily scheduled for odd-numbered years (e.g., 2025, 2027). This scheduling intentionally separates local issues and offices from state and federal partisan races.', 'https://codes.ohio.gov/ohio-revised-code/section-3501.01', 'Ohio Rev. Code § 3501.01', '2026-05-12', 'static', 'statute_citation', 'Municipal and School Board Candidates', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('82e52108c17e4b1d', 'OH', '["municipal"]', 'election_dates', 'How do charter cities in Ohio handle election scheduling differently than statutory cities?', '["Cleveland municipal election rules","Home Rule Amendment Ohio voting","Charter city election exemptions"]', 'Under the Home Rule Amendment of the Ohio Constitution, charter cities (like Cleveland, Cincinnati, and Columbus) have the authority to alter their local municipal election dates, runoff mechanics, and nonpartisan structures independently of the state''s default statutory city frameworks.', 'https://codes.ohio.gov/ohio-constitution/section-18.7', 'Ohio Constitution Article XVIII § 7', '2026-05-12', 'static', 'statute_citation', 'Municipal Candidates in Charter Cities', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('97dfb9db9d570d6b', 'OH', '["state"]', 'ballot_access', 'How can the Ohio General Assembly place a constitutional amendment on the ballot?', '["Legislative resolution for constitutional amendment OH","How does the legislature change the Ohio constitution?","3/5 supermajority rule"]', 'In addition to citizen initiatives, the Ohio General Assembly can place a constitutional amendment directly on the ballot by passing a joint resolution. This requires a three-fifths (60%) supermajority vote in both the State House and State Senate.', 'https://codes.ohio.gov/ohio-constitution/section-16.1', 'Ohio Constitution Article XVI § 1', '2026-05-12', 'static', 'statute_citation', 'State Legislators and Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('4fb820f33dd038be', 'OH', '["state","county","municipal"]', 'finance_ethics', 'What are the digital advertising disclosure rules for Ohio campaigns?', '["Do Facebook ads need disclaimers in Ohio?","Digital political ad rules OH","Internet campaign finance disclaimer"]', 'Paid digital and internet political advertising in Ohio must include clear ''Paid for by'' disclaimers, mirroring the transparency requirements mandated for print and broadcast media under Ohio Election Law.', 'https://codes.ohio.gov/ohio-revised-code/section-3517.20', 'Ohio Rev. Code § 3517.20', '2026-05-12', 'static', 'statute_citation', 'Digital Strategists and Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1'),
  ('9062337610dae06e', 'OH', '["state","county","municipal"]', 'finance_ethics', 'Does Ohio have a public matching funds program or ''doing business'' contribution limits like New York City?', '["Public campaign financing OH","Doing business limits Ohio","Does the state match small donations?"]', 'No. Unlike jurisdictions such as New York City, Ohio does not have a taxpayer-funded public matching funds program, nor does it enforce specific ''doing business'' contribution limit reductions for state or local candidates.', 'https://www.ohiosos.gov/campaign-finance/', 'Ohio Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'All Campaigns', 'batch_2026-05-13T00-03-31_ohio_full_v1')
